package com.google.gson.internal.reflect;
import com.google.gson.JsonIOException;
import com.google.gson.internal.GsonBuildConfig;
import java.lang.reflect.Constructor;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.AccessibleObject;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class ReflectionHelperTest {

  private static Class<?> recordClass;
  private static Class<?> nonRecordClass;

  @BeforeAll
  static void setup() {
    recordClass = RecordExample.class;
    nonRecordClass = NonRecordExample.class;
  }

  @Test
  void isRecord_shouldReturnTrueForRecord() {
    assertTrue(ReflectionHelper.isRecord(recordClass));
  }

  @Test
  void isRecord_shouldReturnFalseForNonRecord() {
    assertFalse(ReflectionHelper.isRecord(nonRecordClass));
  }

  @Test
  void isRecord_shouldReturnFalseForNull() {
    assertFalse(ReflectionHelper.isRecord(null));
  }

  // Helper record class for testing
  public record RecordExample(String name, int age) {}

  // Helper normal class for testing
  public static class NonRecordExample {
    private String name;
    private int age;
  }
}
